import { Column, Entity, OneToMany } from 'typeorm';

import { Session } from '@/app/models/session';
import { TeamDeletionRecord } from '@/app/models/team-deletion-record';
import { TeamPlan } from '@/app/models/team-plan';
import { TeamSubscription } from '@/app/models/team-subscription';
import { User } from '@/app/models/user';
import { UserRole } from '@/app/models/user-role';

export enum TeamType {
  SINGLE = 'single',
  MULTIPLE = 'multiple',
}

@Entity('teams', { schema: 'public' })
export class Team {
  @Column('uuid', {
    primary: true,
    name: 'id',
    default: () => 'gen_random_uuid()',
  })
  id: string;

  @Column('text', { name: 'name' })
  name: string;

  @Column('timestamp with time zone', {
    name: 'created_at',
    default: () => 'now()',
  })
  createdAt: Date;

  @Column('uuid', { name: 'owner_user_id', nullable: true, unique: true })
  ownerUserId: string | null;

  @Column('timestamp with time zone', {
    name: 'updated_at',
    default: () => 'now()',
  })
  updatedAt: Date;

  @Column('timestamp with time zone', {
    name: 'deletion_scheduled_at',
    nullable: true,
  })
  deletionScheduledAt: Date | null;

  @Column('timestamp with time zone', {
    name: 'deleted_at',
    nullable: true,
  })
  deletedAt: Date | null;

  @Column('text', { name: 'image_url', nullable: true })
  imageUrl: string | null;

  @Column('varchar', {
    name: 'billing_failure_reason',
    length: 1023,
    nullable: true,
  })
  billingFailureReason: string | null;

  @Column('varchar', {
    name: 'billing_retry_scheduled_at',
    nullable: true,
  })
  billingRetryScheduledAt: Date | null;

  @Column('timestamp with time zone', {
    name: 'team_plan_cancel_at',
    nullable: true,
  })
  teamPlanCancelAt: Date | null;

  @Column('timestamp with time zone', {
    name: 'team_plan_downgrade_at',
    nullable: true,
  })
  teamPlanDowngradeAt: Date | null;

  @Column('uuid', {
    name: 'downgrade_plan_id',
    nullable: true,
  })
  downgradePlanId: string | null;

  @Column({
    type: 'varchar',
    name: 'team_type',
    length: 31,
    default: TeamType.MULTIPLE,
  })
  teamType: TeamType;

  presignedImageUrl: string | null = null;

  users: User[];
  teamPlan: TeamPlan | null;
  nextTeamPlan: TeamPlan | null;

  @OneToMany(() => TeamPlan, (teamPlan) => teamPlan.team)
  teamPlans: TeamPlan[];

  @OneToMany(
    () => TeamSubscription,
    (teamSubscription) => teamSubscription.team,
  )
  teamSubscriptions: TeamSubscription[];

  @OneToMany(() => Session, (session) => session.team)
  sessions: Session[];

  @OneToMany(
    () => TeamDeletionRecord,
    (teamDeletionRecord) => teamDeletionRecord.team,
  )
  teamDeletionRecords: TeamDeletionRecord[];

  @OneToMany(() => UserRole, (userRole) => userRole.team)
  userRoles: UserRole[];

  // @OneToOne(() => User, (user) => user.teams)
  // @JoinColumn([{ name: 'owner_user_id', referencedColumnName: 'id' }])
  //   ownerUser: User
}

