  async handleInvoicePaymentFailed(event: StripeWebhookEvent): Promise<void> {
    const cbuilder = this.getCodeBuilder();

    const result = await this.datasource.manager.transaction(async (t) => {
      // TODO: TeamSubscription: migrate
      const teamPlan = await t.findOne(TeamPlan, {
        where: {
          stripeSubscription: {
            subscriptionId: event.subscriptionId!,
          },
        },
        relations: {
          stripeSubscription: true,
        },
      });

      if (!teamPlan) {
        throw new CodedException(
          this.code,
          this.EC.INVALID_STRIPE_SUBSCRIPTION(cbuilder.build()),
        );
      }

      const stripeSubscription = await this.stripeProvider.retrieveSubscription(
        event.subscriptionId!,
      );

      // Schedule the invoice retry 1 hour before the subscription period ends.
      // We schedule it because the stripe auto retry will be executed few hours after the subscription period ends.
      await t.update(
        Team,
        { id: teamPlan.teamId },
        {
          billingFailureReason: 'stripe_payment_failed',
          billingRetryScheduledAt: moment(stripeSubscription.currentPeriodStart)
            .add(23, 'hours')
            .toDate(),
          teamPlanCancelAt: moment(stripeSubscription.currentPeriodStart)
            .add(1, 'day')
            .toDate(),
        },
      );

      return { id: teamPlan.id };
    });
  }", "relative_path": "servers/api/src/app/services/payment-sessions.service.ts"}]

