  async handleAppleSubscriptionFailedRenewal(
    event: AppleNotification,
  ): Promise<void> {
    const cbuilder = this.getCodeBuilder();

    await this.datasource.manager.transaction(async (t) => {
      if (!event.renewalInfo || !event.transactionInfo) {
        throw new CodedException(
          this.code,
          this.EC.INVALID_APPLE_SUBSCRIPTION(cbuilder.build()),
        );
      }

      const team = await t.findOne(Team, {
        where: {
          id: event.transactionInfo.appAccountToken,
        },
      });

      if (!team) {
        throw new CodedException(
          this.code,
          this.EC.INVALID_APPLE_SUBSCRIPTION(cbuilder.build()),
        );
      }

      await t.update(
        Team,
        { id: team.id },
        {
          billingFailureReason: 'apple_payment_failed',
          billingRetryScheduledAt: new Date(event.transactionInfo.expiresDate),
        },
      );

      return;
    });
  }", "relative_path": "servers/api/src/app/services/payment-sessions.service.ts"}]

